DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "contextFraction.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context("LimitedFraction"); $ans=Fraction(5,8);
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis} [ numberline, xmin=-1.5, xmax=1.5, minor xtick={-1.375,-1.25,...,1.375}, xtick={-1,0,1}, xlabel={\(x\)}, width=\orccaprintwidth ] \addplot[soliddot] coordinates {(0.625,0)}; \end{axis} \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML In the given number line, what fraction is marked?
>> [@image(insertGraph($image_1), width=>600, alt=>qq"a number line with -1, 0, and 1 marked; there are evenly spaced ticks, with eight ticks between -1 and 0, eight between 0 and 1, and so on; there is a dot marked at the fifth tick to the right from 0")@]* <<
[_]{$ans}{5}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION There are [`8`] subdivisions between [`0`] and [`1\text{,}`] and the mark is at the fifth subdivision. So the mark is [`\frac{5}{8}`] of the way from [`0`] to [`1`] and therefore represents the fraction [`\frac{5}{8}\text{.}`]
END_PGML_SOLUTION
